module RefModule(clk,datavalid,pix_in,pix_out1,pix_out2);
parameter length=640;
input clk,datavalid,pix_in;
output pix_out1,pix_out2;
reg [length-1:0] obf_R;
always@(posedge clk)begin
	if(datavalid)begin
		obf_R[length-1:1]<=obf_R[length-2:0];
		obf_R[0]<=pix_in;
	end
end
assign pix_out1=obf_R[length-1];
assign pix_out2=obf_R[length-2];
endmodule
